import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void twoChars() {
        // bella has b,e,l,a · label has l,a,b,e · roller has r,o,l,e
        // common: e, l
        assertEquals("el", new Solution().commonChars(new String[]{"bella", "label", "roller"}));
    }

    @Test
    void cAndO() {
        assertEquals("co", new Solution().commonChars(new String[]{"cool", "lock", "cook"}));
    }

    @Test
    void singleWord() {
        // distinct chars of "banana" sorted: a, b, n
        assertEquals("abn", new Solution().commonChars(new String[]{"banana"}));
    }

    @Test
    void noCommonChars() {
        assertEquals("", new Solution().commonChars(new String[]{"abc", "def"}));
    }

    @Test
    void emptyArray() {
        assertEquals("", new Solution().commonChars(new String[]{}));
    }
}
